INSERT INTO equipment_stage_json_stream
SELECT
    SUBSTRING(recordData, 1, INSTR(recordData, ',') - 1) AS SERVICE,
    SUBSTRING(recordData, INSTR(recordData, 'host=') + 5, INSTR(recordData, ',', INSTR(recordData, 'host='), 1) - INSTR(recordData, 'host=') - 5) AS HOST,
    SUBSTRING(recordData, INSTR(recordData, 'port_id=') + 8, INSTR(recordData, ',', INSTR(recordData, 'port_id='), 1) - INSTR(recordData, 'port_id=') - 8) AS PORT_ID,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'bandwidth=') + 10, INSTR(recordData, ',', INSTR(recordData, 'bandwidth='), 1) - INSTR(recordData, 'bandwidth=') - 10) AS INT) AS BANDWIDTH,
    SUBSTRING(recordData, INSTR(recordData, 'system_id=') + 10, INSTR(recordData, ',', INSTR(recordData, 'system_id='), 1) - INSTR(recordData, 'system_id=') - 10) AS SYSTEM_ID,
    SUBSTRING(recordData, INSTR(recordData, 'system_type=') + 12, INSTR(recordData, ' ', INSTR(recordData, 'system_type='), 1) - INSTR(recordData, 'system_type=') - 12) AS SYSTEM_TYPE,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'octets_rx=') + 10, INSTR(recordData, ',', INSTR(recordData, 'octets_rx='), 1) - INSTR(recordData, 'octets_rx=') - 10) AS DOUBLE) AS OCTETS_RX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'octets_tx=') + 10, INSTR(recordData, ',', INSTR(recordData, 'octets_tx='), 1) - INSTR(recordData, 'octets_tx=') - 10) AS DOUBLE) AS OCTETS_TX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'unicast_rx=') + 11, INSTR(recordData, ',', INSTR(recordData, 'unicast_rx='), 1) - INSTR(recordData, 'unicast_rx=') - 11) AS DOUBLE) AS UNICAST_RX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'unicast_tx=') + 11, INSTR(recordData, ',', INSTR(recordData, 'unicast_tx='), 1) - INSTR(recordData, 'unicast_tx=') - 11) AS DOUBLE) AS UNICAST_TX,
    REPLACE(SUBSTRING(recordData, INSTR(recordData, 'op_state=') + 9, INSTR(recordData, ',', INSTR(recordData, 'op_state='), 1) - INSTR(recordData, 'op_state=') - 9), '"', '') AS OP_STATE,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'discards_tx=') + 12, INSTR(recordData, ',', INSTR(recordData, 'discards_tx='), 1) - INSTR(recordData, 'discards_tx=') - 12) AS DOUBLE) AS DISCARDS_TX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'discards_rx=') + 12, INSTR(recordData, ',', INSTR(recordData, 'discards_rx='), 1) - INSTR(recordData, 'discards_rx=') - 12) AS DOUBLE) AS DISCARDS_RX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'multicast_rx=') + 13, INSTR(recordData, ',', INSTR(recordData, 'multicast_rx='), 1) - INSTR(recordData, 'multicast_rx=') - 13) AS DOUBLE) AS MULTICAST_RX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'multicast_tx=') + 13, INSTR(recordData, ',', INSTR(recordData, 'multicast_tx='), 1) - INSTR(recordData, 'multicast_tx=') - 13) AS DOUBLE) AS MULTICAST_TX,
    REPLACE(SUBSTRING(recordData, INSTR(recordData, 'collectorHost=') + 14, INSTR(recordData, ',', INSTR(recordData, 'collectorHost='), 1) - INSTR(recordData, 'collectorHost=') - 14), '"', '') AS COLLECTOR_HOST,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'errors_tx=') + 10, INSTR(recordData, ',', INSTR(recordData, 'errors_tx='), 1) - INSTR(recordData, 'errors_tx=') - 10) AS DOUBLE) AS ERRORS_TX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'errors_rx=') + 10, INSTR(recordData, ',', INSTR(recordData, 'errors_rx='), 1) - INSTR(recordData, 'errors_rx=') - 10) AS DOUBLE) AS ERRORS_RX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'broadcast_tx=') + 13, INSTR(recordData, ',', INSTR(recordData, 'broadcast_tx='), 1) - INSTR(recordData, 'broadcast_tx=') - 13) AS DOUBLE) AS BROADCAST_TX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'broadcast_rx=') + 13, INSTR(recordData, ',', INSTR(recordData, 'broadcast_rx='), 1) - INSTR(recordData, 'broadcast_rx=') - 13) AS DOUBLE) AS BROADCAST_RX,
    REPLACE(SUBSTRING(recordData, INSTR(recordData, 'taskId=') + 7, INSTR(recordData, ',', INSTR(recordData, 'taskId='), 1) - INSTR(recordData, 'taskId=') - 7), '"', '') AS taskId,
    REPLACE(SUBSTRING(recordData, INSTR(recordData, 'admin_state=') + 12, INSTR(recordData, ',', INSTR(recordData, 'admin_state='), 1) - INSTR(recordData, 'admin_state=') - 12), '"', '') AS ADMIN_STATE,
    REPLACE(SUBSTRING(recordData, INSTR(recordData, 'connector=') + 10, INSTR(recordData, ',', INSTR(recordData, 'connector='), 1) - INSTR(recordData, 'connector=') - 10), '"', '') AS "CONNECTOR",
    CAST(SUBSTRING(recordData, INSTR(recordData, 'utilization_rx=') + 15, INSTR(recordData, ',', INSTR(recordData, 'utilization_rx='), 1) - INSTR(recordData, 'utilization_rx=') - 15) AS DOUBLE) AS UTILIZATION_RX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'utilization_tx=') + 15, INSTR(recordData, ',', INSTR(recordData, 'utilization_tx='), 1) - INSTR(recordData, 'utilization_tx=') - 15) AS DOUBLE) AS UTILIZATION_TX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'nunicast_rx=') + 12, INSTR(recordData, ',', INSTR(recordData, 'nunicast_rx='), 1) - INSTR(recordData, 'nunicast_rx=') - 12) AS DOUBLE) AS NUNICAST_RX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'nunicast_tx=') + 12, INSTR(recordData, ',', INSTR(recordData, 'nunicast_tx='), 1) - INSTR(recordData, 'nunicast_tx=') - 12) AS DOUBLE) AS NUNICAST_TX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'total_pkts_rx=') + 14, INSTR(recordData, ',', INSTR(recordData, 'total_pkts_rx='), 1) - INSTR(recordData, 'total_pkts_rx=') - 14) AS DOUBLE) AS TOTAL_PKTS_RX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'total_pkts_tx=') + 14, INSTR(recordData, ',', INSTR(recordData, 'total_pkts_tx='), 1) - INSTR(recordData, 'total_pkts_tx=') - 14) AS DOUBLE) AS TOTAL_PKTS_TX,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'discards_rx_pct=') + 16, INSTR(recordData, ',', INSTR(recordData, 'discards_rx_pct='), 1) - INSTR(recordData, 'discards_rx_pct=') - 16) AS DOUBLE) AS DISCARDS_RX_PCT,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'discards_tx_pct=') + 16, INSTR(recordData, ',', INSTR(recordData, 'discards_tx_pct='), 1) - INSTR(recordData, 'discards_tx_pct=') - 16) AS DOUBLE) AS DISCARDS_TX_PCT,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'errors_rx_pct=') + 14, INSTR(recordData, ',', INSTR(recordData, 'errors_rx_pct='), 1) - INSTR(recordData, 'errors_rx_pct=') - 14) AS DOUBLE) AS ERRORS_RX_PCT,
    CAST(SUBSTRING(recordData, INSTR(recordData, 'errors_tx_pct=') + 14, INSTR(recordData, ' ', INSTR(recordData, 'errors_tx_pct='), 1) - INSTR(recordData, 'errors_tx_pct=') - 14) AS DOUBLE) AS ERRORS_TX_PCT,
    SUBSTRING(recordData, INSTR(recordData, 'collection_ts=') + 15, 14) AS COLLECTION_TS,
    SUBSTRING(recordData, INSTR(recordData, 'datetimeutc=') + 13, 14) AS DATETIMEUTC,
    REPLACE(SUBSTRING(recordData, INSTR(recordData, ' ', -1, 1)), ' ', '') AS "time"
FROM equipment_stage_stream
WHERE SUBSTRING(recordData, 1, INSTR(recordData, ',') - 1) = '73xx_if_pm';